    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xFB15FF46E0C0D34FULL + 0xBB33F2F88AAA316BULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xBD0A2118830B1ED9ULL + 0xDD7BA55840557945ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xA532FAA10007FDB1ULL + 0xCB76F513DB51F504ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0xB9701A3A76173479ULL + 0x81A52FB9C564CA21ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0xFCF3C73746C330BDULL + 0xAF82C92141D25D9DULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0xBFFE355D34EEB7F9ULL + 0xE00BE6965457072AULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0xB1DB4F9C5D94D4FDULL + 0xCF982ED40A77CEC7ULL);
