            aOrbiterD = ((((aWandererJ + RotL64(aPrevious, 39U)) + RotL64(aCarry, 3U)) + 6706415615001182471U) + aOrbiterAssignSaltF[(((31U - aIndex) + 22U)) & S_SALT1]) + aNonceWordF;
