            aOrbiterK = (aOrbiterK + aOrbiterC) + 11418498880341891783U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterK) ^ 10057451603818689648U) ^ aOrbiterUpdateSaltB[((aIndex + 26U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 3108813985143051951U), 41U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterD) + 13445316279949627001U;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 7421045777456780102U;
            aOrbiterF = RotL64((aOrbiterF * 15459249679409834705U), 27U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterI) + 13955120698103285270U;
            aOrbiterC = (aOrbiterC ^ aOrbiterG) ^ 3556876928958310160U;
            aOrbiterC = RotL64((aOrbiterC * 11663527586949028021U), 57U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterH) + 9829605342224332105U;
            aOrbiterA = (aOrbiterA ^ aOrbiterD) ^ 4670521908702931926U;
            aOrbiterA = RotL64((aOrbiterA * 15097307411055425405U), 51U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterJ) + 14594824007655519796U;
            aOrbiterE = ((aOrbiterE ^ aOrbiterI) ^ 15208202583897793852U) ^ aOrbiterUpdateSaltE[((aIndex + 29U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 12960269234272970229U), 35U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterE) + 10710410258104724423U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterC) ^ 14573407754372934018U) ^ aOrbiterUpdateSaltD[((aIndex + 25U)) & S_SALT1];
