            //
            aOrbiterA = (aOrbiterA + aOrbiterG) + 2221764890359455543U;
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 1615880637863989135U;
            aOrbiterK = RotL64((aOrbiterK * 8785825319552769583U), 3U);
            //
            aOrbiterJ = (((aOrbiterJ + aOrbiterK) + 6474537089361680510U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 9U)) & S_SALT1]) + aNonceWordK;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 11831057747985600646U;
