            aIngress = aIngress + (aOrbiterH ^ RotL64(aOrbiterJ, 27U));
            aIngress = aIngress + RotL64(aOrbiterE, 39U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererC = aWandererC ^ ((RotL64(aPrevious, 3U) + RotL64(aOrbiterG, 3U)) + aOrbiterC);
            aWandererI = aWandererI + ((((RotL64(aCross, 37U) + aOrbiterA) + RotL64(aOrbiterC, 37U)) + RotL64(aCarry, 35U)) + aNonceWordG);
            aWandererH = aWandererH ^ ((RotL64(aScatter, 41U) + RotL64(aOrbiterF, 41U)) + aOrbiterA);
